t.script:
(function() {
    function clearMgmtParams() {
        if (!window.history || !window.location) return;
        var url = new URL(window.location.href);
        ['mgmt_success', 'mgmt_error', 'mgmt_message'].forEach(function(param) {
            url.searchParams.delete(param);
        });
        window.history.replaceState(null, '', url.toString());
    }

    var alertEl = document.querySelector('.consent_mgmt_alert');
    if (!alertEl) {
        clearMgmtParams();
        return;
    }

    setTimeout(function() {
        if (window.bootstrap && window.bootstrap.Alert) {
            var alertInstance = window.bootstrap.Alert.getOrCreateInstance(alertEl);
            alertInstance.close();
        } else {
            alertEl.classList.remove('show');
            alertEl.classList.add('fade');
            alertEl.style.display = 'none';
        }
        clearMgmtParams();
    }, 4000);
})();

div.script:
(function() {
    var modalNodes = document.querySelectorAll('.consent_mgmt_modal');
    for (var i = 0; i < modalNodes.length; i++) {
        var modalNode = modalNodes[i];
        if (modalNode && modalNode.parentNode !== document.body) {
            document.body.appendChild(modalNode);
        }
    }

    var multiSelectNodes = document.querySelectorAll('.consent_mgmt_multi_select');
    var escapeHtml = function(text) {
        return String(text || '').replace(/[&<>"']/g, function(char) {
            return {
                '&': '&amp;',
                '<': '&lt;',
                '>': '&gt;',
                '"': '&quot;',
                "'": '&#39;'
            }[char];
        });
    };
    var getSelectedLabels = function(checkboxes) {
        var selected = [];
        for (var i = 0; i < checkboxes.length; i++) {
            if (checkboxes[i].checked) {
                selected.push((checkboxes[i].closest('label') || checkboxes[i].parentNode).innerText.trim());
            }
        }
        return selected;
    };
    var buildSummaryMarkup = function(selected, defaultText) {
        if (!selected.length) {
            return '<span class="consent_mgmt_multi_select_placeholder">' + escapeHtml(defaultText) + '</span>';
        }
        return selected.map(function(label) {
            return '<span class="consent_mgmt_multi_select_chip">' + escapeHtml(label) + '</span>';
        }).join('');
    };

    for (var j = 0; j < multiSelectNodes.length; j++) {
        (function(node) {
            var summaryText = node.querySelector('.consent_mgmt_multi_select_summary_text');
            var defaultText = summaryText ? (summaryText.getAttribute('data-default-text') || summaryText.textContent.trim()) : 'Select';
            var checkboxes = node.querySelectorAll('input[type="checkbox"][name="role_ids"]');
            var refreshSummary = function() {
                var selected = getSelectedLabels(checkboxes);
                if (summaryText) {
                    summaryText.innerHTML = buildSummaryMarkup(selected, defaultText);
                }
                if (node.classList) {
                    node.classList.toggle('has-selection', !!selected.length);
                }
            };

            for (var k = 0; k < checkboxes.length; k++) {
                checkboxes[k].addEventListener('change', refreshSummary);
            }
            refreshSummary();
        })(multiSelectNodes[j]);
    }
})();
